/**
 * 工具参数类型定义
 */
export type ToolParameterType = 'string' | 'number' | 'boolean' | 'object' | 'array';
/**
 * 工具参数定义
 */
export interface ToolParameter {
    /**
     * 参数名称
     */
    name: string;
    /**
     * 参数类型
     */
    type: ToolParameterType;
    /**
     * 参数描述
     */
    description?: string;
    /**
     * 是否必需
     */
    required?: boolean;
    /**
     * 枚举值（仅适用于string类型）
     */
    enum?: string[];
    /**
     * 对象属性定义（仅在type为'object'时使用）
     */
    properties?: Record<string, Omit<ToolParameter, 'name'>>;
    /**
     * 数组元素类型定义（仅在type为'array'时使用）
     */
    items?: Omit<ToolParameter, 'name'>;
}
/**
 * 工具定义接口
 */
export interface Tool {
    /**
     * 工具名称（唯一标识）
     */
    name: string;
    /**
     * 工具描述，供大模型理解用途
     */
    description: string;
    /**
     * 工具参数定义
     */
    parameters: ToolParameter[];
    /**
     * 工具异步执行函数
     */
    handler: (...args: any[]) => Promise<any>;
}
/**
 * 工具描述（用于大模型调用）
 */
export interface ToolDescription {
    name: string;
    description: string;
    parameters: ToolParameter[];
}
/**
 * 工具注册器类，提供工具注册、查找、执行和描述生成功能
 */
export declare class ToolRegistry {
    /**
     * 工具存储
     */
    private tools;
    constructor();
    /**
     * 注册一个工具
     * @param tool 工具定义
     */
    register(tool: Tool): void;
    /**
     * 根据名称获取工具
     * @param name 工具名称
     * @returns 工具定义或undefined
     */
    get(name: string): Tool | undefined;
    /**
     * 修改工具配置
     * @param name 工具名称
     * @param tool 工具部分配置
     */
    set(name: string, tool: Partial<Tool>): void;
    /**
     * 注销工具
     * @param name 工具名称
     */
    unregister(name: string): void;
    /**
     * 获取所有工具
     * @returns 所有已注册的工具数组
     */
    getAll(): Tool[];
    /**
     * 检查工具是否存在且可执行
     * @param name 工具名称
     * @returns 是否存在
     */
    has(name: string): boolean;
    /**
     * 异步执行工具
     * @param name 工具名称
     * @param args 参数数组
     * @returns 工具执行结果
     * @throws 当工具不存在或执行出错时抛出异常
     */
    execute(name: string, args?: any[]): Promise<any>;
    /**
     * 生成工具描述列表，供大模型使用
     * @returns 工具描述数组
     */
    generateToolDescriptions(): ToolDescription[];
    /**
     * 清除所有工具
     */
    clear(): void;
}
